#include "interface.h"
#include <cuda_runtime.h>

namespace {

__inline__ __device__ int warp_reduce_sum(int v) {
  unsigned mask = 0xffffffffu;
  v += __shfl_down_sync(mask, v, 16);
  v += __shfl_down_sync(mask, v, 8);
  v += __shfl_down_sync(mask, v, 4);
  v += __shfl_down_sync(mask, v, 2);
  v += __shfl_down_sync(mask, v, 1);
  return v;
}

__global__ void reduce_i32_kernel(const int* __restrict__ input, int* __restrict__ output, int n) {
  int sum = 0;

  const int tid = threadIdx.x;
  const int global_thread = blockIdx.x * blockDim.x + tid;
  const int stride = blockDim.x * gridDim.x;

  for (int idx = global_thread; idx < n; idx += stride) {
    sum += input[idx];
  }

  sum = warp_reduce_sum(sum);

  __shared__ int warp_sums[8];
  const int lane = tid & 31;
  const int warp = tid >> 5;

  if (lane == 0) warp_sums[warp] = sum;
  __syncthreads();

  if (warp == 0) {
    int block_sum = (lane < (blockDim.x >> 5)) ? warp_sums[lane] : 0;
    block_sum = warp_reduce_sum(block_sum);
    if (lane == 0) atomicAdd(output, block_sum);
  }
}

}  // namespace

void add_reduce_i32(const int* input, int* output, int n, int iters) {
  if (iters <= 0) return;

  int block = 256;
  int grid;

  if (n <= 0) {
    grid = 1;
  } else {
    grid = (n + block - 1) / block;
    if (grid > 1024) grid = 1024;
    if (grid < 1) grid = 1;
  }

  for (int iter = 0; iter < iters; ++iter) {
    cudaMemset(output, 0, sizeof(int));
    reduce_i32_kernel<<<grid, block>>>(input, output, n);
  }
}
